414	function void rvv_scoreboard::final_phase(uvm_phase phase);
415	  super.final_phase(phase);
416	
417	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "rvv_total_inst", this.rvv_total_inst)) begin
418	    `uvm_fatal(get_type_name(), "Fail to get rvv_total_inst!")
419	  end
420	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "rvv_excuted_inst", this.rvv_executed_inst)) begin
421	    `uvm_fatal(get_type_name(), "Fail to get rvv_executed_inst!")
422	  end
423	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "mdl_total_inst", this.mdl_total_inst)) begin
424	    `uvm_fatal(get_type_name(), "Fail to get mdl_total_inst!")
425	  end
426	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "mdl_excuted_inst", this.mdl_executed_inst)) begin
427	    `uvm_fatal(get_type_name(), "Fail to get mdl_executed_inst!")
428	  end
429	
430	  // Memory compare
431	  `uvm_info("FINAL_CHECK", "Checking memory...", UVM_LOW)
432	  foreach(test_top.env.lsu_agt.lsu_drv.mem.mem[idx]) begin
433	    if(test_top.env.lsu_agt.lsu_drv.mem.mem[idx] !== test_top.env.mdl.mem.mem[idx])
434	      `uvm_error("FINAL_CHECK", $sformatf("Memory mismatch: lsu_mem[0x%8x] = 0x%2x, mdl_mem[0x%8x] = 0x%2x.", idx, test_top.env.lsu_agt.lsu_drv.mem.mem[idx], idx, test_top.env.mdl.mem.mem[idx]))
435	  end
436	  `uvm_info("FINAL_CHECK", "Memory check pass.", UVM_LOW)
437	
438	  // Queue check
439	  if(rt_queue_rvs.size()>0) begin
440	    `uvm_error("FINAL_CHECK", "rt_queue_rvs wasn't empty!")
441	    foreach(rt_queue_rvs[idx]) begin
442	      `uvm_error("FINAL_CHECK",rt_queue_rvs[idx].sprint())
443	    end
444	  end
445	  if(rt_queue_mdl.size()>0) begin
446	    `uvm_error("FINAL_CHECK", "rt_queue_mdl wasn't empty!")
447	    foreach(rt_queue_mdl[idx]) begin
448	      `uvm_error("FINAL_CHECK",rt_queue_mdl[idx].sprint())
449	    end
450	  end
451	  if(vrf_queue_rvs.size()>0) begin
452	    `uvm_error("FINAL_CHECK", "vrf_queue_rvs wasn't empty!")
453	    foreach(vrf_queue_rvs[idx]) begin
454	      `uvm_error("FINAL_CHECK",vrf_queue_rvs[idx].sprint())
455	    end
456	  end
457	  if(vrf_queue_mdl.size()>0) begin
458	    `uvm_error("FINAL_CHECK", "vrf_queue_mdl wasn't empty!")
459	    foreach(vrf_queue_mdl[idx]) begin
460	      `uvm_error("FINAL_CHECK",vrf_queue_mdl[idx].sprint())
461	    end
462	  end
463	
464	  // Executed inst num check
465	  if(rvv_executed_inst !== mdl_executed_inst) begin
466	    `uvm_error("FINAL_CHECK", "Executed instruction number mismatch.")
467	  end
468	  `uvm_info(get_type_name(),"Exit final_phase...", UVM_HIGH)
469	endfunction: final_phase
470	`endif // RVV_SCOREBOARD__SV
